import PackageBoxAlt from "@iconify-react/lets-icons/package-box-alt";
import Sertificate from "@iconify-react/lets-icons/sertificate";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { createFileRoute, useNavigate } from "@tanstack/react-router";
import { format } from "date-fns";
import { Archive, Building2, Edit, FileText, Hash, MapPin, StickyNote } from "lucide-react";
import { useState } from "react";

import AuditLogs, { type AuditLogEntry } from "@/components/audit-logs";
import NavLayout from "@/components/layouts/nav-layout";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { Skeleton } from "@/components/ui/skeleton";
import type { ClientLocation } from "@/db-schemas/client";
import { rpc } from "@/rpc/client";

import { ClientForm } from "./-form";

export const Route = createFileRoute("/(protected)/(app)/clients/$clientId")({
  component: ClientDetailPage,
});

type ClientDetail = {
  archived: boolean;
  assignee: {
    id: string;
    image: string | null;
    name: string | null;
  };
  assigneeId: string;
  createdAt: Date | null;
  description: string | null;
  id: number;
  internalNotes: string | null;
  legalName: string | null;
  locations: ClientLocation[] | null;
  logo: string | null;
  name: string;
  slug: string;
  updatedAt: Date | null;
};

function ClientDetailPage() {
  const { clientId } = Route.useParams();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const numericId = Number.parseInt(clientId, 10);

  const { data: clientData, isLoading } = useQuery(
    rpc.client.getById.queryOptions({ input: { id: numericId } }),
  );

  const client = clientData as ClientDetail | undefined;

  const { data: eventsData } = useQuery(
    rpc.client.listEvents.queryOptions({
      input: { clientId: numericId },
    }),
  );

  const events =
    (eventsData as { items: AuditLogEntry[] } | undefined)?.items ?? [];

  const [isEditing, setIsEditing] = useState(false);

  const archiveMutation = useMutation({
    mutationFn: () => rpc.client.archive.call({ id: numericId }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["client"] });
      navigate({ to: "/clients" });
    },
  });

  if (isLoading) {
    return (
      <NavLayout
        baseUrl="/clients"
        label="Clients"
        leftItems={<Skeleton className="h-4 w-32" />}
      >
        <div className="space-y-8">
          <div className="space-y-3">
            <Skeleton className="h-7 w-48" />
            <Skeleton className="h-4 w-64" />
            <Skeleton className="h-4 w-40" />
          </div>
          <Separator />
          <div className="grid grid-cols-[auto_1fr] gap-x-12 gap-y-3">
            {Array.from({ length: 5 }).map((_, i) => (
              // biome-ignore lint/suspicious/noArrayIndexKey: skeleton placeholders
              <Fragment key={i}>
                <Skeleton className="h-4 w-24" />
                <Skeleton className="h-4 w-36" />
              </Fragment>
            ))}
          </div>
        </div>
      </NavLayout>
    );
  }

  if (!client) {
    return (
      <NavLayout baseUrl="/clients" label="Clients">
        <p className="text-muted-foreground">Client not found</p>
      </NavLayout>
    );
  }

  const hasExtraSections =
    client.description ||
    (client.locations && client.locations.length > 0) ||
    client.internalNotes;

  return (
    <NavLayout
      baseUrl="/clients"
      label="Clients"
      leftItems={<span className="font-medium">{client.name}</span>}
      rightItems={
        !isEditing ? (
          <div className="flex items-center gap-1.5">
            <Button
              onClick={() => setIsEditing(true)}
              size="sm"
              variant="outline"
            >
              <Edit className="h-3.5 w-3.5" />
              Edit
            </Button>
            {!client.archived && (
              <Button
                disabled={archiveMutation.isPending}
                onClick={() => archiveMutation.mutate()}
                size="sm"
                variant="outline"
              >
                <Archive className="h-3.5 w-3.5" />
                Archive
              </Button>
            )}
            <Button
              onClick={() =>
                navigate({
                  search: { clientId: client.id, clientName: client.name },
                  to: "/job-mandates",
                })
              }
              size="sm"
              variant="outline"
            >
              <PackageBoxAlt className="h-3.5 w-3.5" />
              Job Mandates
            </Button>
            <Button
              onClick={() =>
                navigate({
                  search: { clientId: client.id, clientName: client.name },
                  to: "/contracts",
                })
              }
              size="sm"
              variant="outline"
            >
              <Sertificate className="h-3.5 w-3.5" />
              Contracts
            </Button>
          </div>
        ) : null
      }
    >
      <div className="space-y-8">
        {isEditing ? (
          <ClientForm
            clientId={numericId}
            defaultValues={{
              assigneeId: client.assigneeId,
              internalNotes: client.internalNotes ?? "",
              legalName: client.legalName ?? "",
              locations: client.locations ?? [],
              logo: client.logo ?? undefined,
              name: client.name,
              slug: client.slug,
            }}
            mode="edit"
            onCancel={() => setIsEditing(false)}
            onSuccess={() => setIsEditing(false)}
          />
        ) : (
          <>
            <div className="space-y-2">
              <div className="flex items-center gap-2">
                <h1 className="font-semibold text-xl">{client.name}</h1>
                {client.archived && (
                  <Badge variant="destructive">Archived</Badge>
                )}
              </div>
              {client.legalName && (
                <p className="text-muted-foreground text-sm">
                  {client.legalName}
                </p>
              )}
              <div className="flex items-center gap-2">
                <Avatar className="h-5 w-5">
                  <AvatarImage src={client.assignee.image ?? undefined} />
                  <AvatarFallback>
                    {client.assignee.name?.[0] ?? "?"}
                  </AvatarFallback>
                </Avatar>
                <span className="text-sm">{client.assignee.name}</span>
              </div>
              <div className="text-muted-foreground text-xs">
                Created{" "}
                {client.createdAt
                  ? format(new Date(client.createdAt), "MMM d, yyyy")
                  : "—"}
                {client.updatedAt && (
                  <>
                    {" · "}Updated{" "}
                    {format(new Date(client.updatedAt), "MMM d, yyyy")}
                  </>
                )}
              </div>
            </div>

            <Separator />

            <dl className="grid grid-cols-[auto_1fr] gap-x-12 gap-y-3">
              <dt className="flex items-center gap-1.5 text-muted-foreground text-sm">
                <Hash className="h-3.5 w-3.5" />
                ID
              </dt>
              <dd>
                <code className="rounded bg-muted px-1.5 py-0.5 text-xs">
                  {client.id}
                </code>
              </dd>

              <dt className="text-muted-foreground text-sm">Nickname</dt>
              <dd className="font-medium text-sm">{client.name}</dd>

              {client.legalName && (
                <>
                  <dt className="text-muted-foreground text-sm">Legal Name</dt>
                  <dd className="font-medium text-sm">{client.legalName}</dd>
                </>
              )}

              <dt className="text-muted-foreground text-sm">Slug</dt>
              <dd>
                <code className="rounded bg-muted px-1.5 py-0.5 text-xs">
                  {client.slug}
                </code>
              </dd>

              <dt className="text-muted-foreground text-sm">Assignee</dt>
              <dd className="flex items-center gap-2 font-medium text-sm">
                <Avatar className="h-5 w-5">
                  <AvatarImage src={client.assignee.image ?? undefined} />
                  <AvatarFallback>
                    {client.assignee.name?.[0] ?? "?"}
                  </AvatarFallback>
                </Avatar>
                {client.assignee.name}
              </dd>
            </dl>

            {hasExtraSections && <Separator />}

            {client.description && (
              <div className="space-y-2">
                <div className="flex items-center gap-2 font-medium text-sm">
                  <FileText className="h-4 w-4" />
                  Description
                </div>
                <p className="text-sm leading-relaxed">{client.description}</p>
              </div>
            )}

            {client.locations && client.locations.length > 0 && (
              <div className="space-y-2">
                <div className="flex items-center gap-2 font-medium text-sm">
                  <MapPin className="h-4 w-4" />
                  Locations
                </div>
                <div className="flex flex-wrap gap-1.5">
                  {client.locations.map((loc) => (
                    <Badge
                      key={`${loc.city}-${loc.country}`}
                      variant="secondary"
                    >
                      {loc.city}, {loc.country}
                    </Badge>
                  ))}
                </div>
              </div>
            )}

            {client.internalNotes && (
              <div className="space-y-2">
                <div className="flex items-center gap-2 font-medium text-sm">
                  <StickyNote className="h-4 w-4" />
                  Internal Notes
                </div>
                <p className="text-sm leading-relaxed">
                  {client.internalNotes}
                </p>
              </div>
            )}

            <Separator />

            <AuditLogs domainName="client" entries={events} />
          </>
        )}
      </div>
    </NavLayout>
  );
}

