export default function AuditLogs({ entries }: AuditLogsProps) {
  if (entries.length === 0) return null;
  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Clock className="h-4 w-4" />
          Audit Logs
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="space-y-3">
          {entries.map((entry) => (
            <div className="flex items-start gap-3" key={entry.id}>
              <div className="mt-1.5 h-2 w-2 shrink-0 rounded-full bg-neutral-400" />
              <div className="min-w-0 flex-1 text-sm">
                <PersonPopover entry={entry} />
                <span className="text-muted-foreground"> changed </span>
                <span className="font-medium">{entry.field}</span>
                {entry.oldValue && (
                  <span className="text-muted-foreground">
                    {" "}
                    from &ldquo;{entry.oldValue}&rdquo;
                  </span>
                )}
                {entry.newValue && (
                  <span className="text-muted-foreground">
                    {" "}
                    to &ldquo;{entry.newValue}&rdquo;
                  </span>
                )}
                <span> &middot; </span>
                {entry.changedAt && (
                  <TooltipProvider>
                    <Tooltip>
                      <TooltipTrigger className="cursor-default text-muted-foreground">
                        {formatRelativeTime(entry.changedAt)}
                      </TooltipTrigger>
                      <TooltipContent>
                        {format(
                          new Date(entry.changedAt),
                          "MMM d, yyyy h:mm a",
                        )}
                      </TooltipContent>
                    </Tooltip>
                  </TooltipProvider>
                )}
              </div>
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  );
}

